var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"여기가...... 그 전설의 휴양지인가?","JPN":"ここが……あの伝説のリゾート地？","ENG":"Is this the legendary resort?","TWN":"這裡就是……傳說中的度假勝地嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"확실히 경치가 엄청 좋긴 하네.","JPN":"確かに絶景だね。","ENG":"It does look beautiful.","TWN":"景色確實很美。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GAP_DJ_NULL_NULL","text":{"KOREA":"육지에서도 나의 소울은 멈추지 않지!","JPN":"陸地でも俺のソウルは止められない！","ENG":"Mah music don't stop even when Dis DJ here be on land!","TWN":"在陸地上我的靈魂也不會停止燃燒的！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_DJ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GAP_DJ_NULL_NULL","text":{"KOREA":"자아! 손을 들고 더욱 크게 외치라고! 청춘들이여!","JPN":"さぁ！　手を上に挙げて叫ぶんだ！　青春たちよ！","ENG":"Now, putcha hands up and shout! Aw-yeah! Aw-yeah!","TWN":"來！舉手歡呼吧！青春啊！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_DJ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GAP_DJ_NULL_NULL","text":{"KOREA":"백사장을 달굴 다음 곡은 <color=#83dcb7>나의 관리자는 스윗큐트뷰리풀</color>!","JPN":"白い砂浜を熱くする次の曲は<color=#83dcb7>私の管理者はスウィートキュートビューティフル</color>！","ENG":"My next song to heat up da beach be <color=#83dcb7>My Administrator Is Sweet, Cute, Beautiful</color>!","TWN":"下一首歌是<color=#83dcb7>我的管理者是甜美可愛的小甜心</color>！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_DJ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"와아아아아!!","JPN":"わああああぁ！","ENG":"Waaaah!","TWN":"哇啊啊啊啊！！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_DJ_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"G.A.P! G.A.P!","JPN":"G.A.P！　G.A.P!","ENG":"G.A.P.! G.A.P.!","TWN":"G.A.P！ G.A.P！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_DJ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"저 로봇. 아무리 봐도 닮았단 말이지.","JPN":"あのロボット、どう見ても似てるんだよね。","ENG":"That robot looks so similar to Boss.","TWN":"那個機器人不管怎麼看，都好眼熟。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"......의외로 흔한 디자인인가?","JPN":"……意外とありふれたデザインなの？","ENG":"Maybe it's just a common design.","TWN":"……難道是很常見的設計？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"으, 고막 울려. 저런 쿵쿵대는 음악이 뭐가 좋다고 다들 신나있는 거람?","JPN":"うぅ、鼓膜が。あんな音楽のどこがいいっていうの？","ENG":"Gah, my ears are ringing. I don't understand why people like such loud music.","TWN":"呃，耳朵好痛。那種吵鬧的音樂有什麼好聽的，大家幹嘛那麼興奮？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"그래? 난 엄청 신나는데!","JPN":"そう？　私はすっごく楽しいけど！","ENG":"Don't you? But I love it!","TWN":"是嗎？我覺得很令人興奮啊！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"리듬에 맞춰서 폴짝폴짝 뛰고 있으면 다 같이 한 마음이 된 것 같다구!","JPN":"リズムに合わせてピョンピョン跳ねてると、みんなと気持ちが一つになれた気がするの！","ENG":"When I'm hopping to the music, I feel as if I've become one with the others!","TWN":"只要跟著節奏跳起來，就會覺得大家都是都心意相通的！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"와아...... 인간이 모두 한 마음이 된다고요?","JPN":"わぁ……みんなと気持ちが一つに？","ENG":"Oooo, become one with other humans, huh?","TWN":"哇……人類可以心意相通？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"으악! 까, 깜짝이야!","JPN":"うわっ！　び、びっくりした！","ENG":"Wah! G-geez!","TWN":"啊啊！嚇、嚇我一跳！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"당신 어디서 나타난 거죠? 온 몸이 흠뻑 젖어 있잖아요?","JPN":"どこから現れたんですか？　体中、びしょ濡れですよ？","ENG":"W-where the heck did you come from? You're dripping.","TWN":"妳是從哪裡冒出來的？怎麼全身都濕了？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"아, 괜찮아요. 좀 멀리서 헤엄쳐 오느라......","JPN":"あぁ、大丈夫です。少し遠くから泳いで来たので……","ENG":"Oh, we're okay. We came swimming from afar.","TWN":"喔，沒事的，我們是從很遠的地方游過來的……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"몸에 해초랑 따개비랑...... 문어다리 같은 것도 붙어 있는데? 대체 어디서부터 헤엄을 쳐온 거야?","JPN":"体に海藻とフジツボと……タコの足みたいなものがついてますけど、いったいどこから泳いできたんですか！？","ENG":"You're covered with seaweed, barnacles, and... octopus arms? Just how far have you come swimming?","TWN":"妳身體上黏著海藻和藤壺……還有章魚腿？到底是從哪裡游過來的啊？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"그나저나, 저런 음악을 들으면 여러분도 하나가 될 수 있는 건가요?","JPN":"それより、ああいう音楽を聞くと皆さんも一つになれるんですか？","ENG":"By the way, can you become one, listening to music like that?","TWN":"那個，聽了那樣的音樂，你們真的可以合為一體嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"그럼! 물론이지! 음악에는 사람들을 하나로 만들어주는 마법 같은 힘이 있거든!","JPN":"もちろん！　音楽にはみんなを一つにする魔法みたいな力があるの！","ENG":"Sure. Absolutely! Music has the power to unite people.","TWN":"是啊！當然啦！音樂能把大家都連在一起，有著魔法般的力量呢！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"난 빼주시죠. 저런 걸 누구나 좋아하는 건 아니라고요..","JPN":"私は違います。誰もがあのような音楽が好きだとは限りませんから。","ENG":"Not for me. Not everyone likes music like that.","TWN":"別算上我，並不是所有人都喜歡聽那種音樂。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"으음, 흥미롭지만 말로만 들어선 측량하기 어려운 지식이네요.","JPN":"う～ん、興味深いですが……言葉で聞いただけではわからない知識ですね。","ENG":"Mm, it sounds interesting, but it's difficult to measure solely based on your testimonies.","TWN":"嗯，這個知識雖然很有趣，但光用說的，似乎很難測量呢。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"부학회장님께 제대로 보고 드리려면 어쩔 수 없이 여러분들을 지식의 성찬으로 삼는 게 좋겠어요.","JPN":"副学会長にちゃんと報告するには、致し方ありませんが皆さんを知識の聖餐にするしかなさそうですね。","ENG":"We're sorry, but we'll have to have a feast of knowledge on you, to properly report to the Vice President later.","TWN":"為了能向副會長好好報告，我們只好把各位當作知識的盛宴了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"엥?","JPN":"えっ？","ENG":"Huh?","TWN":"嗯？？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"지식의 성찬이라니 그게 무슨 소리죠?","JPN":"知識の聖餐って、どういう意味ですか？","ENG":"A feast of knowledge? What does that mean?","TWN":"知識的盛宴是什麼意思？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"걱정 마세요, 고통은 찰나일 뿐...... 이제 저희의 일부가 되어 함께 하는 거에요.","JPN":"心配は要りません。苦痛は一瞬です……そして我々の一部となるのです。","ENG":"Don't worry. The pain won't last long. You'll become part of us and live inside us.","TWN":"不用擔心，痛苦只是一時的……成為我們的一部分吧。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"잘 먹겠어요.","JPN":"おいしくいただきます。","ENG":"Thank you for the feast.","TWN":"那我開動了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_WIND_03"},{"id":"L40_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"......어라?","JPN":"……あら？","ENG":"Huh?","TWN":"……咦？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_WIND_03"},{"id":"L43_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"가, 갑자기 사라졌어! 어디로 간 거지?","JPN":"き、消えた！？　どこに行ったの？","ENG":"She disappeared all of a sudden! Where did she go?","TWN":"突、突然消失了！去哪裡了？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"앗! 그러고 보니 이 섬에 귀신이 있다는 얘길 들은 거 같기도......","JPN":"あっ、そういえばこの島に幽霊がいるって聞いたような……","ENG":"Ah, now that I think of it, I might have heard that this island is haunted...","TWN":"啊！我聽說這個島上會鬧鬼……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"귀, 귀신이라니! 불길한 소리 하지 말아요!!","JPN":"ゆ、幽霊！？　そんな不吉なこと言わないでください！","ENG":"H-haunted? Don't say something so creepy!","TWN":"妳、妳說鬼！別說不吉利的話啦！！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"어머나~ 오랜만에 뵈어요. 벌써 깨어나셨나 보네요. 아스모데......","JPN":"あら、お久しぶりです。もう目覚めたのですか？　アスモデ……","ENG":"Oh, long time, no see. You're already awake, Asmode—","TWN":"哎呀～好久不見，妳已經醒來啦，阿斯蒙蒂……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"시끄러! 이 문어 사촌아! 여기서 그 이름은 금지야!","JPN":"うるさい！　このタコ従姉妹め！　ここでその名前は禁句じゃ！","ENG":"Shut up, you octopus cousin! That name is forbidden here!","TWN":"閉嘴！妳這個章魚腦袋！在這裡禁止說那個名字！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"여기에 있는 건 우아하고 현명한 사랑의 마왕, 로자리아님 뿐이라고!","JPN":"ここにいるのは優雅で賢明な愛の魔王、ロザリア様だけじゃ！","ENG":"What's here now is the elegant and wise Demon Lord of Love, Rosaria!","TWN":"這裡只有優雅賢明的愛情魔王，羅莎莉亞！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"아, 그런가요? 수식어가 자주 바뀌시네요.","JPN":"あっ、そうですか？　名前がよく変わるのですね。","ENG":"Oh, is it? It seems modifiers for your name keep changing.","TWN":"哦，是嗎？妳的外號變得可真快呢。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"그나저나 넌 몸뚱이만 조각이 난 게 아니라 눈치도 조각이 나버렸냐?","JPN":"それより其方は体がバラバラになったと思ったら、空気も読めなくなったようじゃな？","ENG":"By the way, did you lose your senses when your body was ripped to shreds?","TWN":"看樣子妳不只有身體被粉碎，連臉色都不會看了啊？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"왜 남이 차린 판에 끼어들어서 행패를 부려?","JPN":"人の邪魔をするだけじゃ飽き足らず、悪事を働くとは何事じゃ？","ENG":"Why are you trying to rain on my parade?","TWN":"妳來這裡是在搞什麼鬼？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"네? 저희가 또 무슨 실수를 한 건가요? 저흰 그저 지식을 얻으려고 온 것뿐인데......","JPN":"はい？　我々が何かしたと言うのですか？　ただ知識を手に入れに来ただけですが……","ENG":"Sorry? What did we do wrong this time? We only came here to gain some knowledge.","TWN":"咦？我們又做錯什麼了嗎？我們只是來獲取知識的耶……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"흥, 지식이고 허기고 늘 먹어서 해결하려고만 하니까 그렇게 사고가 단순해지지.","JPN":"ふん、知識だろうと飢えだろうと、いつも食して解決しようとするから、単純な思考しかできなくなるのじゃ。","ENG":"Knowledge? Hmpf, you mean food. You always try to solve things by just eating them up. No wonder you've become such a simpleton.","TWN":"哼，什麼知識，就只會用吃來解決飢餓感，怪不得思考越來越單純。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"난 지금 바쁘니까 힘 자랑은 나중에 클리포트 게임에서나 하라고!","JPN":"妾は今忙しいのじゃ。力比べはクリフォトゲームでやればよい。","ENG":"I'm busy right now. You can show off your power later during the Qliphoth Game.","TWN":"我現在很忙，妳還是把力氣留到逆卡巴拉遊戲再用吧！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"오늘은 불꽃놀이 구경이나 하면서 얌전히 있다가 가는 거야. 알겠지?!","JPN":"今日は花火大会を見ながらおとなしくしているのじゃ、わかったか？","ENG":"For now, I want you to just watch the fireworks and stay quietly. Got it?","TWN":"今天妳就乖乖欣賞煙火，乖乖不要搗亂，知道了嗎？！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"으음...... 그렇게 소득 없이 돌아갔다간 레지나 님께서 실망하실 텐데요......","JPN":"う～ん……手ぶらで帰ってしまったらレジーナさんをがっかりさせてしまいます……","ENG":"Mm... But Miss Regina would be disappointed if we return empty-handed.","TWN":"嗯……但是空手而歸的話，蕾佳娜大人會失望的……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"레지나는 또 뭐 하는 녀석인지 모르겠다만, 네가 여기서 먹자 파티를 벌이면 아마 백배는 더 실망할 거다.","JPN":"レジーナが何をしてるやつかは知らぬが、其方がここで晩餐会を開こうものなら、\\nその数百倍はがっかりすることになるぞ？","ENG":"I don't know who this Regina is, but she'd be much more disappointed in you if you binge on these partygoers here.","TWN":"我不知道蕾佳娜是誰，但如果妳在這裡開美食派對的話，我想她會失望一百倍的。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"애초에 굶주린 짐승 노릇이나 하려고 인간들의 축제까지 보내진 건 아닐 텐데?","JPN":"そもそも飢えた獣遊びをさせるために、人間どもの祭りに送り込んだわけじゃなかろう？","ENG":"She didn't send you to this human festival just so you could act like a hungry beast, did she?","TWN":"她派妳到人類的慶典，應該不是要妳當隻飢餓的野獸吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"앗, 맞아요! 제게 인간다움을 배우라고 보내셨거든요.","JPN":"あっ、そうでした！　人間らしさを学べと言われたのです。","ENG":"Oh, no. She sent us here to learn how to be human.","TWN":"啊，對喔！她是為了讓我們像個人類，所以才派我來的。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"그래, 자고로 인간다움이란 축제에서 소란을 피우지 않는 것이 기본소양이지.","JPN":"そうじゃ。参考までに人間らしさというのものは、祭りで騒ぎを起こさぬことを言うのじゃぞ。","ENG":"Okay, then you shouldn't cause trouble at the festival because humans don't do that.","TWN":"對，要像個人類的基本素養，就是不在派對中引起騷動。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"으음......","JPN":"う～ん……","ENG":"Mm...","TWN":"唔……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"알겠어요. 저희 최대한 얌전히 있으려고 노력해볼게요.","JPN":"わかりました。我々はおとなしくするよう努力します。","ENG":"Okay. We'll do our best to behave.","TWN":"知道了，我們會儘量乖乖的。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"......후우.","JPN":"ふぅ……","ENG":"*Sigh*","TWN":"……呼。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"겨우 여기까지 왔는데도 하는 짓이라곤 들킬까 봐 숨어 다니는 것뿐이네.","JPN":"ここまで来たのに、見つからないよう隠れながら歩かないといけないなんて。","ENG":"I didn't come this far just to hide from my possible pursuers.","TWN":"好不容易來到這裡，結果卻只能偷偷摸摸的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아니, 멀쩡히 돌아다닐 상황이라도 별로 다른 건 없겠지. 나 같은 걸 누가 쳐다봐 주겠어?","JPN":"いや、普通に歩いててもバレないんじゃ？　私なんかどうせ誰も見てくれないし。","ENG":"But then, even if I didn't have to hide, nothing would change. Who would take an interest in a woman like me?","TWN":"也沒有吧，即使不偷偷摸摸的也沒有什麼不同，誰會注意到像我這樣的人呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"역시 난 뭘 해도 안 되는 거야.","JPN":"やっぱり私は何をしてもダメなんだ。","ENG":"I can't win, no matter how hard I try.","TWN":"我果然什麼也做不好。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"어째 안 보인다 했더니, 넌 또 왜 이런 곳에 숨어서 끙끙대고 있어?","JPN":"最近見当たらないと思っていたら、其方はなぜこんなところで隠れてぶつぶつ言っておるのじゃ？","ENG":"I wondered where you were. Why are you hiding in here, groaning?","TWN":"我說怎麼沒看到妳，結果妳又一個人躲在這種地方嘀咕些什麼呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"로, 로자리아님?","JPN":"ロ、ロザリアさん？","ENG":"L-Lady Rosaria.","TWN":"羅、羅莎莉亞大人？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"네가 가려는 길에 방해되는 게 있다면 망설이지 말고 치워버려라.","JPN":"其方が進む道を邪魔するものがあるのなら、躊躇せずに消し去るのじゃ。","ENG":"If something gets in your way, you shouldn't hesitate to get rid of it.","TWN":"只要是擋住妳去路的人，妳都要毫不猶豫地把他們解決掉。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그게 두렵다면, 네가 찾는 운명의 상대는 그럴 정도의 가치도 없었다는 건가?","JPN":"それを恐れていては其方が探す運命の相手は、その程度の価値しかないということになるのだぞ？","ENG":"If you can't even do that, how are you going to find your soul mate?","TWN":"如果妳不敢，就代表你的命運之人沒有那種價值。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"넌 영원히 혼자가 될 운명을 벗어나기 위해서 그 감옥을 탈출한 거잖아?","JPN":"其方は永遠にひとりぼっちの運命から抜け出すために、脱獄したのじゃろう？","ENG":"You escaped the prison to get away from your destined loneliness, didn't you?","TWN":"為了擺脫永遠是一個人的命運，妳才會逃獄的不是嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그런데 이제 와서 뭘 두려워하는 거냐?","JPN":"なのに今さら何を恐れておるのじゃ。","ENG":"Why are you afraid now?","TWN":"既然這樣，事到如今妳又在怕什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"내가 찾는 운명의 상대......","JPN":"私が探す運命の相手……","ENG":"My soul mate...","TWN":"我要找的命運之人……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"맞아! 외롭고 쓸쓸하게 늙는 게 억울해서 탈옥까지 저질렀는데, 고작 방해꾼 몇 때문에 포기할 수는......!","JPN":"そう！　一人寂しく老いてくのが悔しくて脱獄までしたのに、この程度の障害で諦めるわけには……！","ENG":"That's right. I escaped because I didn't want to grow old alone. I can't give him up just because of a few hecklers—","TWN":"沒錯！我就是不想要孤獨終老，所以才會逃獄的，我怎麼可以因為幾個小挫折就放棄呢……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"어라......?! 그런데 당신이 그걸 어떻게 알고 있는 거죠?","JPN":"えっ……！？　でもあなたがどうしてそれを？","ENG":"Erm? But how did you know?","TWN":"咦……？！但妳怎麼知道這些事的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"탐정이니까 그 정도 뒷조사는 간단하지.","JPN":"探偵なのじゃぞ？　その程度の情報収集は朝飯前じゃ。","ENG":"I'm a detective. I investigate people for a living.","TWN":"因為我是偵探，想要調查這種事情輕而易舉。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"뭐, 그런 건 너무 신경 쓰지 말거라.","JPN":"まぁ、そんなことはどうでもよい。","ENG":"Well, that's not important.","TWN":"不過，妳不用太在意這些。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"지금 중요한 건 네가 그토록 바라던 운명의 상대가 이곳에 있다는 사실이니까.","JPN":"今重要なのは其方がそれほど望む運命の相手が、ここにいるという事実じゃろう？","ENG":"What matters now is that your soul mate is right here, right now.","TWN":"現在最重要的，是妳夢寐以求的命運之人就在這裡。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"가거라. 네 소원을 위해 무엇을 할 수 있는지, 이 몸이 기꺼이 지켜봐 주마.","JPN":"行くのじゃ。其方の願いを叶えるためにどこまでできるのか、妾が見届けよう。","ENG":"Go. Go do whatever it takes to make your wish come true. I'll watch you from here.","TWN":"去吧，妳能為妳的願望做出什麼事情，我會滿心歡喜地看著的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"내가...... 바라는 것을 얻기 위해 할 수 있는 일......","JPN":"私の……願いを叶えるためにできること……","ENG":"Do whatever it takes to make my wish come true...","TWN":"我……能為我的願望做出什麼事情……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그래. 이런 식으로 정직하게 구애 행위를 해 봤자, 결국 나보다 예쁜 여자들에게 밀려날 뿐.","JPN":"そう。こんな風に求愛行動をしたところで、結局私より可愛い子たちに取られちゃうだけ。","ENG":"You're right. I can never beat pretty girls just by being honest.","TWN":"是啊，就算我正面去追求，也會輸給比我更漂亮的女孩。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"후후. 이런 얌전한 방식으로 이성의 환심을 사려고 하다니. 너무 나약해져 있었네요.","JPN":"ふふっ、こんなおとなしいやり方で異性の心を奪おうとするなんて、私も落ちぶれたものですね。","ENG":"Hah hah. I can't believe I tried to attract men in such a tamed way. I've gotten soft.","TWN":"呵呵，竟然會用這麼老實的方法去討異性的歡心，看來我真的變弱了呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"잊고 있었던 제 본 모습을 일깨워줘서 고마워요, 로자리아......","JPN":"忘れていた私の本当の姿を思い出させてくれてありがとうございます。ロザリア……","ENG":"Thank you for reminding me of who I really am, Lady Rosa—","TWN":"謝謝妳讓我想起我曾經的樣子，羅莎莉亞……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"......님?","JPN":"さん……？","ENG":"—ria?","TWN":"……大人？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_15"},{"id":"L43_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"어디로 사라졌지? 방금 전만해도 여기에 있었는데?","JPN":"どこに消えたの？　さっきまでここにいたのに？","ENG":"Where did she go? She was right here a moment ago.","TWN":"怎麼不見了？明明剛剛還在這裡啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"게다가...... 이 소리는?","JPN":"それに……この音は？","ENG":"And... what's this noise?","TWN":"還有……這個聲音是？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"으하하하, 찾았다! 여기 있었군!","JPN":"うははは、見つけたぞ！　ここにいたのか！","ENG":"Mwa hah hah hah! We've found her!","TWN":"哇哈哈哈，找到了！在這裡啊！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"우린 한 번 찍은 타깃은 절대로 놓치지 않는다! 수단과 방법도 가리지 않지!","JPN":"我々は狙った獲物は決して逃さないのだ！　どんな手を使ってもな！","ENG":"We never miss our target! We're never above using dirty tricks, either!","TWN":"我們一旦鎖定目標就絕對不會放棄！我們會不擇手段的！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"그게 바로 우리 찰거머리 특전대!","JPN":"我らこそは粘着特戦隊！","ENG":"We are the Leech Rangers!","TWN":"這就是我們血蛭特戰隊！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"대장님, 아무리 생각해도 그 이름은 너무 멋이 없다니까요.","JPN":"隊長、やっぱりその名前はダサイです。","ENG":"Captain, I really don't think that name sounds cool.","TWN":"隊長，我還是覺得這個名字很土耶。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"저 귀찮은 녀석들, 여기까지 쫓아온 건가?","JPN":"あのしつこいやつら、ここまでついて来たわけ？","ENG":"I can't believe those gnats have followed us this far.","TWN":"這些討厭的傢伙，竟然追到這裡了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아니지. 오히려 잘 됐어. 저것들을 이제 내가 이용하면 되는 거잖아?","JPN":"いや、むしろ良かったのかもしれない。あいつらを私が利用すればいいだけ。","ENG":"Actually, this is better. I can take advantage of them now.","TWN":"不，這樣反而是好事。我只要利用這一切就行了吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"후후후......","JPN":"ふふふ……","ENG":"Hah hah hah...","TWN":"呵呵呵……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"흐하하하하하!!!","JPN":"あはははは！！","ENG":"Mwa Hah hah hah!","TWN":"哈哈哈哈哈！！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_THUNDER"},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"날씨가 점점 안 좋아지는군요.","JPN":"天気がだんだん悪くなってきましたね。","ENG":"It's getting cloudy.","TWN":"天氣越來越壞了呢。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"그러게. 이러다 비라도 온다면 불꽃놀이는 힘들겠어.","JPN":"本当ね。雨でも降ったら花火大会は中止になるかも……","ENG":"Yes. There will be no fireworks if it rains.","TWN":"是啊，萬一下雨，就沒有煙火表演了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"불길한 구름이야. 일이 순탄치만은 않게 흘러갈 징조로군.","JPN":"不吉な雲だ。事が順調に進まなくなる前兆だな。","ENG":"Those clouds are a bad omen. Things are not going to go smoothly.","TWN":"不祥的雲，這是不祥之兆啊。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_THUNDER"},{"id":"L15_1","type":"dialog","speaker":"GAP_DJ_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_DJ_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_THUNDER"},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"어라, 오늘 축제에 헬기가 동원된다는 얘긴 없지 않았나요?","JPN":"うん？　今日のお祭りにヘリが出動するって言ってましたっけ？","ENG":"Err, did any one of you hear about choppers being mobilized for today's festival?","TWN":"咦，今天的慶典沒說過會動用直升機吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"이봐, 꼬맹이들! 이디스 트윈즈를 넘겨라!","JPN":"そこのお前ら、イーディス・ツインズを渡せ！","ENG":"Hey, kiddos! Hand over Edith Twins to us!","TWN":"喂，小鬼們！把伊蒂絲雙子交出來！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"그렇게 당하고도 또 다시 이렇게 덤벼오다니, 학습능력이 떨어지는 어른들이로군요.","JPN":"まだ懲りないのですか。学習能力の低い大人たちのようですね。","ENG":"You adults haven't learned from your previous lesson, have you?","TWN":"被打敗那麼多次還敢來啊，真是學習能力不佳的大人啊。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"하하, 이번엔 좀 다를 거다! 이쪽도 만반의 준비를 해왔거든!","JPN":"ハハハ、今回は少し違うぞ！　こっちも万全の準備をして来たのだ！","ENG":"Hah hah. Things are going to be different this time! We came fully prepared!","TWN":"哈哈，這次可不一樣！我們做了萬全的準備！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"우리가 원하는 한 명만 순순히 넘기면 나머지 모두의 안전은 보장해주지!","JPN":"そいつを渡せば、他の者たちの安全は保証しよう！","ENG":"Just hand her over, and we'll leave the rest of you alone.","TWN":"只要乖乖把我們要的人交出來，我們就放你們一條生路！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"우와, 엄청나게 3류 악당 같은 대사잖아?","JPN":"うわぁ、ザ・三流悪党みたいな台詞だね？","ENG":"Wow, you totally sound like a third-rate villain right now.","TWN":"哇，這還真是典型的三流反派台詞呢。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"뭐야, 당신들. 감히 누가 누구의 안전을 보장해준다고?","JPN":"あなたたち、何なの？　誰が誰の安全を保証するですって？","ENG":"Who the hell are you? Who asked you to leave us alone?","TWN":"什麼，你們這些傢伙，也不知道是誰放誰一條生路呢？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"어......?","JPN":"うん……？","ENG":"Huh?","TWN":"呃……？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"하아, 바다에선 침식체가 튀어나오더니 이번엔 무장한 납치범들이야?","JPN":"はぁ、海から侵食体が飛び出して来たかと思ったら、今度は武装した誘拐犯？","ENG":"Dang. First, it was C.O.s from the sea, and now it's armed kidnappers.","TWN":"唉，剛才是海裡冒出了侵蝕體，現在是一群武裝綁架犯？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"여기, 세계 최고의 휴양지라며?","JPN":"世界最高のリゾート地じゃなかったの？","ENG":"The world's greatest resort, my butt.","TWN":"這裡不是世界頂級的度假勝地嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_SUMMER_NULL","text":{"KOREA":"불꽃놀이가 곧 시작될 거에요. 그전에 빠르게 처리하도록 하죠.","JPN":"花火大会がもうすぐ始まります。その前に早く片付けてしまいましょう。","ENG":"The fireworks will begin soon. Let's take care of them beforehand.","TWN":"煙火表演馬上就要開始了，儘快解決掉吧。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"어라......?","JPN":"うん……？","ENG":"Huh?","TWN":"咦……？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"대장님. 아까보다 카운터가 훨씬 많아진 것 같은데요?","JPN":"隊長、さっきよりカウンターが増えているような気がしますが……","ENG":"Captain, I think there are more Counters than there were before.","TWN":"隊長，制裁者的數量好像比之前更多了耶？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"그렇다고 여기서 물러날 거 같아? 이쪽도 전력총동원이다!","JPN":"だからって、ここで引き下がるわけにはいかない！　こっちも戦力総動員だ！","ENG":"So what? We're not going to give up. We're going all out!","TWN":"所以你要我們現在撤退嗎？我們也動員了所有戰力！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"여기 보라고! 덕분에 텅텅 비어버린 내 적금통장이 보이나?","JPN":"これを見ろ、すっからかんの貯金通帳を！　有り金全部はたいたんだぞ！","ENG":"Look! My savings account is empty now, thanks to you!","TWN":"你看！我已經花掉了我的所有積蓄！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"이것처럼 싹 밀어버려!","JPN":"俺の通帳残高のように、こいつらを一掃しろ！","ENG":"Wipe them out clean, just like my account!","TWN":"全部解決掉！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}}]`);export{e as default};